const fs = require('fs');
const path = require('path');

// Function to clean up unused imports in a file
function cleanupUnusedImports(filePath) {
  try {
    let content = fs.readFileSync(filePath, 'utf8');
    
    // Check if it's a page.tsx file that was generated by our script
    if (!filePath.includes('page.tsx') || !content.includes('CheckCircle, ArrowRight, Phone, Mail, MapPin, Zap, Shield, Brain, Globe')) {
      return false; // Skip files that weren't generated by our script
    }
    
    console.log(`Cleaning up unused imports in: ${filePath}`);
    
    // Replace the long import with only the used icons
    content = content.replace(
      /import { CheckCircle, ArrowRight, Phone, Mail, MapPin, Zap, Shield, Brain, Globe } from 'lucide-react';/g,
      'import { Shield, Brain, Globe, Zap } from \'lucide-react\';'
    );
    
    // Remove unused benefits array
    content = content.replace(
      /  const benefits = \[\s*'[^']*',\s*'[^']*',\s*'[^']*',\s*'[^']*',\s*'[^']*',\s*'[^']*',\s*'[^']*',\s*'[^']*'\s*\];/g,
      ''
    );
    
    // Write the cleaned content
    fs.writeFileSync(filePath, content);
    return true;
  } catch (error) {
    console.error(`Error cleaning ${filePath}:`, error.message);
    return false;
  }
}

// Function to recursively find all .tsx files in the app directory
function findTsxFiles(dir) {
  const files = [];
  const items = fs.readdirSync(dir);
  
  for (const item of items) {
    const fullPath = path.join(dir, item);
    const stat = fs.statSync(fullPath);
    
    if (stat.isDirectory()) {
      files.push(...findTsxFiles(fullPath));
    } else if (item.endsWith('.tsx') && item === 'page.tsx') {
      files.push(fullPath);
    }
  }
  
  return files;
}

// Main execution
const appDir = path.join(__dirname, 'app');
const tsxFiles = findTsxFiles(appDir);

console.log(`Found ${tsxFiles.length} page.tsx files to check`);

let cleanedCount = 0;
for (const file of tsxFiles) {
  if (cleanupUnusedImports(file)) {
    cleanedCount++;
  }
}

console.log(`Cleaned up unused imports in ${cleanedCount} files`);